var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"이봐. 아직 멀었어?","JPN":"おい、まだなのか？","ENG":"Hey! What's taking so long?","TWN":"喂。還沒修好嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"시끄러워. 고장난 기계가 보챈다고 고쳐지는 줄 알아?","JPN":"少し黙ってろ。壊れた機械を直すのは大変なんだ。","ENG":"Shut it. You think grilling me is going to fix this broken machine any faster?","TWN":"閉嘴。光靠抱怨就能修好機器，你以為能有那麼簡單？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"…놈들이다.","JPN":"……奴らだ。","ENG":"…It's them.","TWN":"……是那些混蛋。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"서둘러…! 침식체들이 동면에서 깨기 시작했다고…!","JPN":"急いでくれ……！　侵食体どもが冬眠から目覚め始めた……！","ENG":"Hurry…! The C.O.s are waking up from hibernation…!","TWN":"動作快點……！侵蝕體要從冬眠裡甦醒了……！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"젠장, 젠장, 젠장.","JPN":"ちくしょ、ちくしょ、ちくしょ！","ENG":"Dammit, dammit, dammit.","TWN":"該死，該死，該死！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"…됐다!","JPN":"……直った！","ENG":"...Done!","TWN":"……搞定了！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"이봐! 해치 열었어!","JPN":"おい、ハッチが開いたぞ！","ENG":"Hey! I got the hatch open!","TWN":"你看！艙門打開了！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"헉헉… 헉…","JPN":"はぁ、はぁ……","ENG":"*Huff* *Huff* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"이 정도면 안전하겠지?","JPN":"ここまで来たらもう安全か？","ENG":"We should be safe now, right?","TWN":"這下安全了嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"안전할 리가. 여긴 5층이야.","JPN":"いや。ここはまだ5階だ。","ENG":"You wish. We're on the 5th floor.","TWN":"怎麼可能，這裡可是地下5層。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"A급 카운터도 여럿 죽은 곳이라고.","JPN":"ここでAランクカウンターが何人もやられてる。","ENG":"Many Grade A Counters died here.","TWN":"據說有好幾個A級制裁者也死在這裡了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"시라사키에서 접선한 의뢰인들이 여기서 카운터 능력을 절대 쓰지 말라고 했었지.","JPN":"シラサキで会った依頼主からは、ここでカウンター能力を使うなと念押しされた。","ENG":"The clients we met at Sirasaki explicitly warned us not to use our Counter abilities here.","TWN":"我在白崎委託人告訴我，永遠不要在這裡使用制裁者能力。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"어때? 정말 CRF 제어가 안돼?","JPN":"どうなんだ？　本当にCRFの制御が利かないのか？","ENG":"So, how is it? Are you really having trouble controlling your CRF?","TWN":"用了會怎樣？CRF真的會失控嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"글쎄. 아직 안 써봐서 잘 모르겠지만…","JPN":"さあな。実際にやってみるまではわからない……","ENG":"Don't know. I can't tell since I haven't used it yet...","TWN":"不清楚，我還沒用過……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"이런 곳에서 쓸 일은 없기를 바라야지.","JPN":"こんな場所で使う羽目にならないことを願っておかなくちゃな。","ENG":"Let's hope I don't have to use it here.","TWN":"總之我希望永遠不會用在這種見鬼的地方……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GUARD_FLOOR_NULL_EXOSUIT","text":{"KOREA":"꺼헉… 헉 헉…","JPN":"ぐっ……はぁ……はぁ……","ENG":"*Huff* *Huff* *Huff...*","TWN":"咳咳……咳哈……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"어이, 이 다친 친구는 어떡해? 지금이라도 승강기 태워서 올려보내야 하나?","JPN":"おい、この怪我人はどうする？　昇降機に乗せて上げておくか？","ENG":"What do we do with our injured buddy here? He's in bad shape. Should we put him on the elevator and send him up?","TWN":"喂，這位受傷的朋友怎麼辦？用升降機把他送上去嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"…보내긴 뭘 보내? 승강기 왕복시키는 데 얼마가 드는지 알아?","JPN":"……何を言ってんだ？　昇降機を往復させるのにいくらかかると思ってるんだよ？","ENG":"...We're not sending anyone up. Do you know how much a round trip on that thing costs?","TWN":"……送什麼送？你知道那東西來回一趟要花多少時間嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"폐가 관통당했어. 어차피 돌아가도 살긴 힘들 거야.","JPN":"肺を貫かれたんだ。帰還したところで助かりはしない。","ENG":"His lung's punctured. He won't make it anyway.","TWN":"我看看……肺已經被穿透。就算現在送他回去，也活不了了。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GUARD_FLOOR_NULL_EXOSUIT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"이제 편히 쉬라고.","JPN":"残念だが安らかに眠ってくれ。","ENG":"Rest in peace.","TWN":"好好安息吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"무능한 가드 놈들… 목적지에 도착하기도 전에 침식체들한테 전부 썰리다니.","JPN":"無能なボディガードたち……目的地にたどり着く前に全員が侵食体にやられやがった。","ENG":"Incompetent guards... They all got wiped by C.O.s before we even arrived at our destination.","TWN":"這些保全真沒用……還沒到目的地，就被侵蝕體全部幹掉了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"아주 쓸모없진 않았어. 우리가 여기까지 올 시간은 벌어줬으니까.","JPN":"だがそれなりに役には立ってくれた。俺たちがここにたどり着くまで盾役になってくれたんだからな。","ENG":"They weren't all useless. They bought time for us to get this far.","TWN":"也不是一點用也沒有。至少給我們爭取時間跑到了這裡。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EXPLORER_FLOOR_COUNTER_NULL","text":{"KOREA":"아까부터 이건 무슨 소리지?","JPN":"さっきからいったいなんの音だ？","ENG":"What's that noise?","TWN":"嗯？剛才那是什麼聲音？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_COUNTER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EXPLORER_FLOOR_EXOSUIT_NULL","text":{"KOREA":"가드가 가지고 있던 탐지기군. CSE 3레벨 이상의 침식파가 감지됐을 때 울리도록 설정해 뒀어.","JPN":"ボディガードが持っていた探知機だ。CSE3レベル以上の侵食派が検知されると鳴るように設定されている。","ENG":"It's the detector the guard had. It's set to go off when it detects CSE level 3 or higher Corruption rays.","TWN":"那個是保全攜帶的探測器。一旦檢測到CSE 3級以上侵蝕波，就會發出警報。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EXPLORER_FLOOR_EXOSUIT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};